const ifItems = $items('Check low stock'); // All Shopify items that passed IF

return items.map((item, index) => {
  const fullText = item.json.text || '';

  const lines = fullText.split('\n').filter(l => l.trim() !== '');

  let subject = 'Low Stock Alert';
  let body = fullText;

  if (lines.length && /^subject:/i.test(lines[0])) {
    subject = lines[0].replace(/^Subject:\s*/i, '');
    body = lines.slice(1).join('\n').trim();
  }

  const shopifyItem = ifItems[index]?.json || {};

  return {
    json: {
      subject,
      body,

      // NOW TRULY DYNAMIC
      sku: shopifyItem.sku ?? 'N/A',
      inventory_quantity: shopifyItem.inventory_quantity ?? 0,
      product_name: shopifyItem.product_name ?? 'Unknown',
      variant_id: shopifyItem.varient_id ?? 0,
      time_stemp: new Date().toISOString()
    }
  };
});

